func nextDraftAction(survey *types.Survey) string {
	if survey.Drafts[len(survey.Drafts)-1].Status == types.DraftStatusPending {
		return "start"
	}

	if survey.Drafts[len(survey.Drafts)-1].Status == types.DraftStatusActive {
		return "finish"
	}
	return "add"
}

